Server-side streaming proxy (SSE) + retry classification (illustrative):

// POST /v1/chat/stream
res.setHeader("Content-Type", "text/event-stream");
res.setHeader("Cache-Control", "no-cache");
res.setHeader("Connection", "keep-alive");

const abort = new AbortController();
req.on("close", () => abort.abort());

const result = await withRetries(async ({ attempt }) => {
  logger.info({ attempt }, "starting upstream request");
  return redwood.streamChat({ model, messages, signal: abort.signal, timeoutMs });
}, { logger, maxAttempts: 4 });

for await (const chunk of result) {
  // forward token deltas to browser
  writeSseEvent(res, "delta", chunk);
}
writeSseEvent(res, "done", "");

// retry.ts
export function isRetryableStatus(code: number) {
  return [408, 409, 425, 429, 500, 502, 503, 504].includes(code);
}

export function computeBackoffMs(attempt: number) {
  const base = Math.min(250 * 2 ** (attempt - 1), 4000);
  return Math.floor(Math.random() * base); // full jitter
}
